import React, { useState } from 'react';

const Cart = () => {
  const [cartItems, setCartItems] = useState([
    { id: 1, name: 'Product 1', price: 10.00, quantity: 2 },
    { id: 2, name: 'Product 2', price: 15.00, quantity: 1 },
    { id: 3, name: 'Product 3', price: 20.00, quantity: 3 }
  ]);

  const increaseQuantity = (id) => {
    setCartItems(cartItems.map(item => {
      if (item.id === id) {
        return { ...item, quantity: item.quantity + 1 };
      }
      return item;
    }));
  };

  const decreaseQuantity = (id) => {
    setCartItems(cartItems.map(item => {
      if (item.id === id && item.quantity > 1) {
        return { ...item, quantity: item.quantity - 1 };
      }
      return item;
    }));
  };

  const calculateTotal = () => {
    return cartItems.reduce((total, item) => total + (item.price * item.quantity), 0).toFixed(2);
  };

  return (
    <div className="container">
      <h1>Shopping Cart</h1>
      <table>
        <thead>
          <tr>
            <th>Product</th>
            <th>Price</th>
            <th>Quantity</th>
            <th>Total</th>
          </tr>
        </thead>
        <tbody>
          {cartItems.map(item => (
            <tr key={item.id}>
              <td>{item.name}</td>
              <td>${item.price.toFixed(2)}</td>
              <td>
                <button onClick={() => decreaseQuantity(item.id)}>-</button>
                <input type="text" value={item.quantity} readOnly />
                <button onClick={() => increaseQuantity(item.id)}>+</button>
              </td>
              <td>${(item.price * item.quantity).toFixed(2)}</td>
            </tr>
          ))}
        </tbody>
        <tfoot>
          <tr>
            <td colSpan="3">Subtotal</td>
            <td>${calculateTotal()}</td>
          </tr>
          <tr>
            <td colSpan="3">Tax (10%)</td>
            <td>${(calculateTotal() * 0.1).toFixed(2)}</td>
          </tr>
          <tr>
            <td colSpan="3"><strong>Total</strong></td>
            <td><strong>${(parseFloat(calculateTotal()) + (parseFloat(calculateTotal()) * 0.1)).toFixed(2)}</strong></td>
          </tr>
        </tfoot>
      </table>
      <button className="checkout-btn">Proceed to Checkout</button>
    </div>
  );
};

export default Cart;
